<?php
namespace App\Jobs;
use App\Models\BugCase; use App\Support\BugInvestigator\BugInvestigator; use Illuminate\Bus\Queueable; use Illuminate\Contracts\Queue\ShouldQueue; use Illuminate\Foundation\Bus\Dispatchable; use Illuminate\Queue\InteractsWithQueue; use Illuminate\Queue\SerializesModels;
class RunBugInvestigationJob implements ShouldQueue { use Dispatchable, InteractsWithQueue, Queueable, SerializesModels; public function __construct(public BugCase $bugCase) {} public function handle(BugInvestigator $investigator): void { $this->bugCase->update(['status'=>'running','started_at'=>now(),'error_message'=>null]); try { $result=$investigator->investigate($this->bugCase->fresh()); $this->bugCase->report()->updateOrCreate([], ['summary'=>$result['summary']??null,'raw_report'=>$result['raw_report']??null,'codex_prompt'=>$result['codex_prompt']??null,'findings'=>$result['findings']??[],'suspected_files'=>$result['suspected_files']??[],'broken_rules'=>$result['broken_rules']??[]]); $this->bugCase->update(['status'=>'completed','finished_at'=>now()]); } catch (\Throwable $e) { $this->bugCase->update(['status'=>'failed','finished_at'=>now(),'error_message'=>$e->getMessage()]); throw $e; } } }
